import{c as n,Q as r,j as s,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Harness Engineering 文章收錄摘要","description":"","frontmatter":{"title":"Harness Engineering 文章收錄摘要","type":"documentation"},"headers":[],"relativePath":"research/ai-articles/HARNESS-ARTICLES-DIGEST.md","filePath":"research/ai-articles/HARNESS-ARTICLES-DIGEST.md","lastUpdated":1779894392000}'),t={name:"research/ai-articles/HARNESS-ARTICLES-DIGEST.md"};function a(i,e,l,g,d,c){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="harness-engineering-文章收錄摘要" tabindex="-1">Harness Engineering 文章收錄摘要 <a class="header-anchor" href="#harness-engineering-文章收錄摘要" aria-label="Permalink to &quot;Harness Engineering 文章收錄摘要&quot;">​</a></h1><blockquote><p>收錄日期：2026-05-08<br> 收錄總數：14 篇（1 篇 Medium paywall 無法存取）<br> 評分標準：深度 × 原創性 × 實用性（★★★★★ 滿分）</p></blockquote><hr><h2 id="★★★★★-必讀-深度-×-實用性最高" tabindex="-1">★★★★★ 必讀（深度 × 實用性最高） <a class="header-anchor" href="#★★★★★-必讀-深度-×-實用性最高" aria-label="Permalink to &quot;★★★★★ 必讀（深度 × 實用性最高）&quot;">​</a></h2><hr><h3 id="_1-the-anatomy-of-an-agent-harness" tabindex="-1">1. The Anatomy of an Agent Harness <a class="header-anchor" href="#_1-the-anatomy-of-an-agent-harness" aria-label="Permalink to &quot;1. The Anatomy of an Agent Harness&quot;">​</a></h3><p><strong>檔案：</strong> <code>anatomy-of-agent-harness.md</code><br><strong>來源：</strong> blog.dailydoseofds.com<br><strong>評分：</strong> ★★★★★</p><p><strong>核心觀點：</strong><br> 目前最完整的 harness 概覽文章。以「LLM = CPU、Context = RAM、Harness = OS」的類比為主軸，系統性拆解 11 個生產組件（Orchestration Loop、Tools、Memory、Context Management、Prompt Construction、Output Parsing、State Management、Error Handling、Guardrails、Verification Loops、Subagent Orchestration）。</p><p><strong>最有價值的部分：</strong></p><ul><li>7 個架構決策矩陣（single vs multi-agent、ReAct vs plan-execute、context 策略等）</li><li>TerminalBench 數據：僅換 harness，LangChain 從第 30 → 第 5；harness 移動 agent 20+ 排名</li><li>ACON 研究：26–54% token 減少，保留 95%+ 精準度</li><li>「Harness Is the Product」核心論點，及 Manus 六個月五次重寫的個案</li></ul><p><strong>適合誰：</strong> 想一次掌握 harness 全貌的人</p><hr><h3 id="_2-agentic-harness-engineering-llms-as-the-new-os" tabindex="-1">2. Agentic Harness Engineering: LLMs as the New OS <a class="header-anchor" href="#_2-agentic-harness-engineering-llms-as-the-new-os" aria-label="Permalink to &quot;2. Agentic Harness Engineering: LLMs as the New OS&quot;">​</a></h3><p><strong>檔案：</strong> <code>agentic-harness-engineering-decodingai.md</code><br><strong>來源：</strong> decodingai.com<br><strong>評分：</strong> ★★★★★</p><p><strong>核心觀點：</strong><br> 從 financial startup 實戰出發，拆掉 LlamaIndex/MCP 框架後用 plain Python 反而更好。強調「harness engineering = 用 LLM 作為 OS 建構真實軟體應用」。</p><p><strong>最有價值的部分：</strong></p><ul><li>Multi-surface architecture（OpenClaw 用 typed WebSocket 一份邏輯服務 CLI/Web/Desktop/Telegram）</li><li>Lane-aware FIFO queue 解決多 client 並發問題</li><li>三層記憶體（Filesystem = 長期、RAM = 短期、Context Window = 當前）的讀寫路徑</li><li>Ralph Loop 跨 context window 長任務模式的最清楚解釋</li><li>誠實的局限說明：記憶跨長 session 仍會斷、100 個平行 agent 共享 codebase 仍是開放問題</li></ul><p><strong>適合誰：</strong> 從零開始設計自訂 harness 的工程師</p><hr><h3 id="_3-agent-engineering-how-the-harness-became-the-product" tabindex="-1">3. Agent Engineering: How the Harness Became the Product <a class="header-anchor" href="#_3-agent-engineering-how-the-harness-became-the-product" aria-label="Permalink to &quot;3. Agent Engineering: How the Harness Became the Product&quot;">​</a></h3><p><strong>檔案：</strong> <code>agent-engineering-morphllm.md</code><br><strong>來源：</strong> morphllm.com<br><strong>評分：</strong> ★★★★★</p><p><strong>核心觀點：</strong><br> Agent engineering 的全景地圖。介紹 swyx 的 IMPACT 框架（Intent、Memory、Planning、Authority、Control Flow、Tools），Manus $2B 收購故事，以及各工具 harness 的橫向比較表。</p><p><strong>最有價值的部分：</strong></p><ul><li>IMPACT 框架 — OpenAI TRIM 框架漏掉 Planning 和 Authority</li><li>Manus 生產洞見：KV-cache 命中率是最關鍵指標（cached token 成本約未 cached 的 1/10）；用 logit masking 而非移除工具（避免 cache 失效）</li><li>Cursor 發現：移除 GPT-5-Codex 的 reasoning trace 導致效能下降 30%</li><li>The Apply Layer：edit 合併是所有 harness 的共同瓶頸，需要獨立的 apply model</li><li>Test-first（Simon Willison）+ Spec-driven（Addy Osmani）工作流的實作範例</li></ul><p><strong>適合誰：</strong> 想深入理解 agent engineering 系統設計的架構師</p><hr><h3 id="_4-harness-engineering-best-practices-for-claude-code-codex-users" tabindex="-1">4. Harness Engineering Best Practices for Claude Code / Codex Users <a class="header-anchor" href="#_4-harness-engineering-best-practices-for-claude-code-codex-users" aria-label="Permalink to &quot;4. Harness Engineering Best Practices for Claude Code / Codex Users&quot;">​</a></h3><p><strong>檔案：</strong> <code>harness-engineering-best-practices-2026-nyosegawa.md</code><br><strong>來源：</strong> nyosegawa.com<br><strong>評分：</strong> ★★★★★</p><p><strong>核心觀點：</strong><br> 2026 最佳實踐集大成。7 個核心原則，從 repo 衛生到 E2E 測試策略全面覆蓋。</p><p><strong>最有價值的部分：</strong></p><ul><li>Linter 速度比較：Oxlint（50–100x faster than ESLint）、Ruff（900+ rules in Rust）</li><li>四種 Hook 模式：Safety Gates（PreToolUse）、Quality Loops（PostToolUse）、Completion Gates（Stop）、Observability</li><li>反饋速度層級：PostToolUse Hook (ms) &gt; pre-commit (s) &gt; CI (min) &gt; 人工 review (h)</li><li>AGENTS.md 大小目標：&lt; 50 行（官方建議 200 行是上限，不是目標）；Claude Code 系統提示約 50 條指令，100 行 CLAUDE.md 會達到退化閾值</li><li>Codex 架構差異：Hooks 僅支援 Bash（2026-03-26 實驗性），Claude Code 覆蓋所有工具</li><li>Minimum Viable Harness 四週漸進 roadmap</li></ul><p><strong>適合誰：</strong> 需要具體實作清單的工程師</p><hr><h2 id="★★★★-深度佳-值得細讀" tabindex="-1">★★★★ 深度佳，值得細讀 <a class="header-anchor" href="#★★★★-深度佳-值得細讀" aria-label="Permalink to &quot;★★★★ 深度佳，值得細讀&quot;">​</a></h2><hr><h3 id="_5-claude-code-harness-runtime-architecture-2026-guide" tabindex="-1">5. Claude Code Harness: Runtime Architecture 2026 Guide <a class="header-anchor" href="#_5-claude-code-harness-runtime-architecture-2026-guide" aria-label="Permalink to &quot;5. Claude Code Harness: Runtime Architecture 2026 Guide&quot;">​</a></h3><p><strong>檔案：</strong> <code>claude-code-harness-runtime-architecture-pasqualepillitteri.md</code><br><strong>來源：</strong> pasqualepillitteri.it<br><strong>評分：</strong> ★★★★</p><p><strong>核心觀點：</strong><br> Claude Code runtime 的 8 個組件深度解析（Tool Executor、Permission Manager、Hook System、Context Manager、MCP Layer、Skill System、Subagent Framework、Session Storage）。</p><p><strong>最有價值的部分：</strong></p><ul><li>Auto mode 的背後機制：Sonnet 4.6 背景安全分類器，只評估 user requests 和 tool calls，不評估 model prose</li><li>Session Storage：JSONL 格式、<code>--fork-session</code>、checkpoint 機制（Escape×2 rewind 只覆蓋 file edits，非遠端副作用）</li><li>Harness token overhead：10K–50K tokens（系統提示、工具定義、CLAUDE.md、auto-memory 最多 25KB）</li><li><code>/context</code> 指令可看即時 token 分配明細</li></ul><p><strong>適合誰：</strong> 想了解 Claude Code 內部機制的開發者</p><hr><h3 id="_6-claude-code-でハーネスエンジニアリングを実践する-5-層設計" tabindex="-1">6. Claude Code でハーネスエンジニアリングを実践する（5 層設計） <a class="header-anchor" href="#_6-claude-code-でハーネスエンジニアリングを実践する-5-層設計" aria-label="Permalink to &quot;6. Claude Code でハーネスエンジニアリングを実践する（5 層設計）&quot;">​</a></h3><p><strong>檔案：</strong> <code>claude-code-harness-engineering-zenn-sasadango.md</code><br><strong>來源：</strong> zenn.dev/sasadango28<br><strong>評分：</strong> ★★★★（日文）</p><p><strong>核心觀點：</strong><br> 個人知識管理 repo 的 5 層設計實踐：CLAUDE.md（憲法）→ Rules（領域規則）→ Skills（可重用工作流）→ Agents（專業子 Agent）→ Settings（安全裝置）。</p><p><strong>最有價值的部分：</strong></p><ul><li><code>globs</code> frontmatter 讓 Rules 延遲載入（條件式），節省 context</li><li>LLM vs Script 責務分離：<code>tech-daily2</code> 用 Python 做 RSS 抓取，LLM 只做翻譯/分類 → token 降至 1/6、時間 1/3</li><li>「寫清楚不做什麼」是最高 CP 值的設計決策</li><li>Hooks 的本質差別：CLAUDE.md 是「建議（advisory）」，Hooks 是「強制（deterministic）」</li></ul><p><strong>適合誰：</strong> Claude Code 個人工作區設計的參考</p><hr><h3 id="_7-codex-vs-claude-code-2026" tabindex="-1">7. Codex vs Claude Code（2026） <a class="header-anchor" href="#_7-codex-vs-claude-code-2026" aria-label="Permalink to &quot;7. Codex vs Claude Code（2026）&quot;">​</a></h3><p><strong>檔案：</strong> <code>codex-vs-claude-code-morphllm.md</code><br><strong>來源：</strong> morphllm.com<br><strong>評分：</strong> ★★★★</p><p><strong>核心觀點：</strong><br> Claude Code 用 3.2–4.2x 更多 token 卻在多項 benchmark 領先。深入比較兩者架構、失敗模式、定價。</p><p><strong>最有價值的部分：</strong></p><ul><li>Token 差距數據：Figma Plugin 任務 Codex ~1.5M vs Claude ~6.2M（4.2x）</li><li>Claude Agent Teams 有依賴追蹤 + 直接訊息；Codex 沒有 inter-agent 協調</li><li>Codex 創新：diff-based memory（差分移除舊 context 而非摘要，保留結構理解）</li><li>Rakuten 案例：12.5M 行 codebase，Claude 數值精準度 99.9%</li><li>混合工作流：Codex 快速 prototype → Claude 架構審查 → Claude Agent Teams 執行 → Codex 收尾</li></ul><p><strong>適合誰：</strong> 評估工具選擇或規劃混合工作流的團隊</p><hr><h3 id="_8-ハーネスエンジニアリング、全員が違うことを言っている-5-社解釈比較" tabindex="-1">8. ハーネスエンジニアリング、全員が違うことを言っている（5 社解釈比較） <a class="header-anchor" href="#_8-ハーネスエンジニアリング、全員が違うことを言っている-5-社解釈比較" aria-label="Permalink to &quot;8. ハーネスエンジニアリング、全員が違うことを言っている（5 社解釈比較）&quot;">​</a></h3><p><strong>檔案：</strong> <code>harness-engineering-interpretations-zenn-kenimo.md</code><br><strong>來源：</strong> zenn.dev/kenimo49<br><strong>評分：</strong> ★★★★（日文）</p><p><strong>核心觀點：</strong><br> 比較 OpenAI、Anthropic、LangChain、Birgitta Böckeler（martinfowler.com）、arXiv 論文對 harness 的不同定義。</p><p><strong>最有價值的部分：</strong></p><ul><li>OpenAI 角度：宣告式約束，人類 steering + 大規模並行</li><li>Anthropic 角度：context anxiety 概念，長時間穩定性優先，盡量 single agent</li><li>LangChain 數據：harness 設計改善讓 benchmark 從 52.8% → 66.5%</li><li>Böckeler 最獨特觀點：TypeScript strict mode / Rust Borrow Checker 本身就是 harness，不需另外建</li><li>三步驟實用起點：寫 AGENTS.md → 自動化品質閘道 → 錯誤回饋循環</li></ul><p><strong>適合誰：</strong> 想理清 harness 概念發展脈絡的研究者</p><hr><h3 id="_9-the-importance-of-agent-harness-in-2026" tabindex="-1">9. The importance of Agent Harness in 2026 <a class="header-anchor" href="#_9-the-importance-of-agent-harness-in-2026" aria-label="Permalink to &quot;9. The importance of Agent Harness in 2026&quot;">​</a></h3><p><strong>檔案：</strong> <code>agent-harness-2026-philschmid.md</code><br><strong>來源：</strong> philschmid.de（Hugging Face）<br><strong>評分：</strong> ★★★★</p><p><strong>核心觀點：</strong><br> Phil Schmid 從「Bitter Lesson」視角論證 harness 為何必須保持輕量。模型的每次改版都可能讓你的「智慧控制邏輯」過時。</p><p><strong>最有價值的部分：</strong></p><ul><li>Benchmark 問題：1% leaderboard 差距無法偵測 50+ tool call 後的指令跟隨穩定性</li><li>Harness 三大作用：驗證真實世界進步、提升使用者體驗上限、提供 hill-climbing 反饋迴路</li><li>Manus 五次重寫、LangChain 三次重構、Vercel 移除 80% 工具的教訓</li><li><strong>「Harness is the Dataset」</strong>：agent 失敗的軌跡是下一代訓練數據的競爭優勢</li><li>訓練與推理環境收斂的預測：harness 將成偵測 model drift 的主要工具</li></ul><p><strong>適合誰：</strong> 想了解 harness 未來發展方向的技術領袖</p><hr><h3 id="_10-what-is-harness-engineering-smartscope-四象限" tabindex="-1">10. What Is Harness Engineering（SmartScope 四象限） <a class="header-anchor" href="#_10-what-is-harness-engineering-smartscope-四象限" aria-label="Permalink to &quot;10. What Is Harness Engineering（SmartScope 四象限）&quot;">​</a></h3><p><strong>檔案：</strong> <code>harness-engineering-overview-smartscope.md</code><br><strong>來源：</strong> smartscope.blog<br><strong>評分：</strong> ★★★★</p><p><strong>核心觀點：</strong><br> harness ⊇ context ⊇ prompt 的嵌套關係，以及四象限設計框架（Architecture constraints、Feedback loops、Workflow control、Improvement cycles）。</p><p><strong>最有價值的部分：</strong></p><ul><li>Can.ac 實驗：僅改工具格式，同一模型從 6.7% → 68.3%（約 10x 改善）</li><li>OpenAI 百萬行案例五大原則：設計環境、機械強制架構、倉庫為單一事實來源、可觀測性、抗熵</li><li>診斷啟發法：「個別輸出偏差」是 context 問題；「重複使用後架構一致性下降」是 harness 問題</li><li>多 agent 並行時 harness 更重要：人覺得麻煩的細粒度邊界，正是 agent 最適合的工作方式</li></ul><p><strong>適合誰：</strong> 快速定位 context vs harness 問題根因</p><hr><h2 id="★★★-實用參考-不需深讀" tabindex="-1">★★★ 實用參考，不需深讀 <a class="header-anchor" href="#★★★-實用參考-不需深讀" aria-label="Permalink to &quot;★★★ 實用參考，不需深讀&quot;">​</a></h2><hr><h3 id="_11-swe-bench-pro-leaderboard-2026" tabindex="-1">11. SWE-Bench Pro Leaderboard（2026） <a class="header-anchor" href="#_11-swe-bench-pro-leaderboard-2026" aria-label="Permalink to &quot;11. SWE-Bench Pro Leaderboard（2026）&quot;">​</a></h3><p><strong>檔案：</strong> <code>swe-bench-pro-morphllm.md</code><br><strong>來源：</strong> morphllm.com<br><strong>評分：</strong> ★★★</p><p><strong>核心觀點：</strong><br> 解釋為何 SWE-bench Verified 80.9% 而 SWE-bench Pro 只有 45.9%。Verified 已被訓練資料污染，Pro 是更可靠的基準。</p><p><strong>關鍵數據：</strong></p><ul><li>Scaffolding gap：同一個 Opus 4.5，三個 agent system 跑出 50.2%–55.4%（5.2pp 差距完全來自 harness）</li><li>Pro vs Verified：平均修改行數 107 vs 11，平均修改檔案數 4.1 vs ~1</li><li>失敗模式分析：semantic understanding 35.9%、context overflow 35.6%、tool-use inefficiency 42%（小模型）</li></ul><p><strong>適合誰：</strong> 需要評估 agent 效能基準的研究者</p><hr><h3 id="_12-claude-code-vs-codex-vs-aider-vs-opencode-vs-pi-2026" tabindex="-1">12. Claude Code vs Codex vs Aider vs OpenCode vs Pi（2026） <a class="header-anchor" href="#_12-claude-code-vs-codex-vs-aider-vs-opencode-vs-pi-2026" aria-label="Permalink to &quot;12. Claude Code vs Codex vs Aider vs OpenCode vs Pi（2026）&quot;">​</a></h3><p><strong>檔案：</strong> <code>ai-coding-harness-agents-2026-jock.md</code><br><strong>來源：</strong> thoughts.jock.pl<br><strong>評分：</strong> ★★★</p><p><strong>核心觀點：</strong><br> 六個工具的快速比較：Claude Code（長任務自主）、Codex CLI（app 開發）、Aider（預算/稽核）、OpenCode（多模型）、Pi（自訂 harness）、Cursor（監督式 IDE）。</p><p><strong>關鍵數據：</strong></p><ul><li>Terminal-Bench 2.0：Claude Code harness 92.1% vs Codex CLI 77.3%</li><li>Aider：4.2x token 效率優勢</li><li>選擇框架：自主隔夜執行 → Claude Code；App 開發 → Codex；預算限制 → Aider</li></ul><p><strong>適合誰：</strong> 快速選工具的工程師</p><hr><h3 id="_13-what-is-an-agent-harness-firecrawl" tabindex="-1">13. What Is an Agent Harness?（Firecrawl） <a class="header-anchor" href="#_13-what-is-an-agent-harness-firecrawl" aria-label="Permalink to &quot;13. What Is an Agent Harness?（Firecrawl）&quot;">​</a></h3><p><strong>檔案：</strong> <code>what-is-agent-harness-firecrawl.md</code><br><strong>來源：</strong> firecrawl.dev<br><strong>評分：</strong> ★★★</p><p><strong>核心觀點：</strong><br> 入門概念文，結合 Firecrawl 服務介紹 harness 的 4 個核心組件。有輕微產品推廣成分。</p><p><strong>值得記錄：</strong></p><ul><li>ICML 2025 遊戲研究：啟用 harness vs 停用 harness，同模型所有遊戲 win-rate 均提升</li><li>harness engineering 定義：「把每次 agent 失敗當成工程問題永久修復，而非重試的 prompt」</li></ul><p><strong>適合誰：</strong> 第一次接觸 harness 概念的入門讀者</p><hr><h3 id="_14-ハーネスエンジニアリングは枠組みから始めよう-caddi" tabindex="-1">14. ハーネスエンジニアリングは枠組みから始めよう（CADDi） <a class="header-anchor" href="#_14-ハーネスエンジニアリングは枠組みから始めよう-caddi" aria-label="Permalink to &quot;14. ハーネスエンジニアリングは枠組みから始めよう（CADDi）&quot;">​</a></h3><p><strong>檔案：</strong> <code>start-harness-engineering-caddi.md</code><br><strong>來源：</strong> caddi.tech<br><strong>評分：</strong> ★★★（日文）</p><p><strong>核心觀點：</strong><br> 降低 harness 整備心理障礙的實踐文章。核心洞見：<strong>框架的存在比內容充實更重要</strong>。空的 Rules 檔案只要放對位置，團隊就會自然填充。</p><p><strong>值得記錄：</strong></p><ul><li><code>/update-coding-rule</code> skill 概念：實作中遇到問題 → 一個指令轉化成品質規則</li><li>Rules index file 設計：<code>.claude/rules/</code> 只放路徑指引，本體另存，minimizes 條件式載入 token</li><li>「開發與 harness 整備不分離」的工作方式：同一個任務完成時順手完善 harness</li></ul><p><strong>適合誰：</strong> 想在既有團隊低阻力導入 harness 的工程師</p><hr><h2 id="無法收錄" tabindex="-1">無法收錄 <a class="header-anchor" href="#無法收錄" aria-label="Permalink to &quot;無法收錄&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章</th><th>原因</th></tr></thead><tbody><tr><td>Building Claude Code with Harness Engineering (levelup.gitconnected.com)</td><td>Medium paywall，只能存取標題/摘要</td></tr></tbody></table><hr><h2 id="閱讀路徑建議" tabindex="-1">閱讀路徑建議 <a class="header-anchor" href="#閱讀路徑建議" aria-label="Permalink to &quot;閱讀路徑建議&quot;">​</a></h2><p><strong>完全新手（30 分鐘入門）：</strong><br> firecrawl → smartscope → philschmid</p><p><strong>工程師（想動手）：</strong><br> anatomy-of-agent-harness → nyosegawa best practices → pasqualepillitteri runtime</p><p><strong>架構師（系統設計）：</strong><br> agent-engineering-morphllm → agentic-harness-engineering-decodingai → interpretations-zenn-kenimo</p><p><strong>工具評估：</strong><br> swe-bench-pro → codex-vs-claude-code → ai-coding-harness-agents-jock</p><p><strong>Claude Code 深度使用者：</strong><br> zenn-sasadango（5 層設計）→ pasqualepillitteri（runtime）→ nyosegawa（best practices）</p><hr><h2 id="跨文章共識-5-篇以上提及" tabindex="-1">跨文章共識（5 篇以上提及） <a class="header-anchor" href="#跨文章共識-5-篇以上提及" aria-label="Permalink to &quot;跨文章共識（5 篇以上提及）&quot;">​</a></h2><ol><li><strong>Harness ⊇ Context ⊇ Prompt</strong> — 嵌套層級，harness 涵蓋一切</li><li><strong>「文件說要跑 linter」≠「Hook 強制跑 linter」</strong> — advisory vs deterministic 的本質差異</li><li><strong>Manus 六個月五次重寫</strong> — harness 需要持續精簡，不是一次建好</li><li><strong>同模型換 harness 效能差 5–22 個百分點</strong> — harness 比模型選擇更影響結果</li><li><strong>Thin harness 趨勢</strong> — 隨模型進步，harness 應該越來越薄；越複雜的控制邏輯越容易被下一個模型版本淘汰</li><li><strong>驗證循環是生產與 Demo 的分水嶺</strong> — 沒有自我驗證能力的 agent 不是生產就緒</li><li><strong>Filesystem 是最基礎的 harness primitive</strong> — 不需要 vector DB，git log + progress.json 已足夠</li></ol>',119)])])}const u=n(t,[["render",a]]);export{p as __pageData,u as default};
